import type { ComponentProps, ComponentRef } from 'react';
import { Switch as SwitchPrimitive, useSwitch, useSwitchContext } from '@ark-ui/react/switch';
import { clsx } from 'clsx';
import { forwardRef } from 'react';
import { normalizeClassName } from '@/lib/moduix/normalizeClassName';
import styles from './Switch.module.css';

type SwitchSize = 'xs' | 'sm' | 'md' | 'lg' | 'xl';

const SwitchRoot = forwardRef<
  ComponentRef<typeof SwitchPrimitive.Root>,
  ComponentProps<typeof SwitchPrimitive.Root> & { size?: SwitchSize }
>(function SwitchRoot({ className, size = 'md', children, ...props }, ref) {
  return (
    <SwitchPrimitive.Root
      ref={ref}
      data-slot="switch-root"
      data-size={size}
      className={clsx(styles.root, normalizeClassName(className))}
      {...props}
    >
      {children ?? (
        <>
          <SwitchControl />
          <SwitchHiddenInput />
        </>
      )}
    </SwitchPrimitive.Root>
  );
});

const SwitchRootProvider = forwardRef<
  ComponentRef<typeof SwitchPrimitive.RootProvider>,
  ComponentProps<typeof SwitchPrimitive.RootProvider> & { size?: SwitchSize }
>(function SwitchRootProvider({ className, size = 'md', children, ...props }, ref) {
  return (
    <SwitchPrimitive.RootProvider
      ref={ref}
      data-slot="switch-root-provider"
      data-size={size}
      className={clsx(styles.root, normalizeClassName(className))}
      {...props}
    >
      {children ?? (
        <>
          <SwitchControl />
          <SwitchHiddenInput />
        </>
      )}
    </SwitchPrimitive.RootProvider>
  );
});

const SwitchControl = forwardRef<
  ComponentRef<typeof SwitchPrimitive.Control>,
  ComponentProps<typeof SwitchPrimitive.Control>
>(function SwitchControl({ className, children, ...props }, ref) {
  return (
    <SwitchPrimitive.Control
      ref={ref}
      data-slot="switch-control"
      className={clsx(styles.control, normalizeClassName(className))}
      {...props}
    >
      {children ?? <SwitchThumb />}
    </SwitchPrimitive.Control>
  );
});

const SwitchThumb = forwardRef<
  ComponentRef<typeof SwitchPrimitive.Thumb>,
  ComponentProps<typeof SwitchPrimitive.Thumb>
>(function SwitchThumb({ className, ...props }, ref) {
  return (
    <SwitchPrimitive.Thumb
      ref={ref}
      data-slot="switch-thumb"
      className={clsx(styles.thumb, normalizeClassName(className))}
      {...props}
    />
  );
});

const SwitchLabel = forwardRef<
  ComponentRef<typeof SwitchPrimitive.Label>,
  ComponentProps<typeof SwitchPrimitive.Label>
>(function SwitchLabel({ className, ...props }, ref) {
  return (
    <SwitchPrimitive.Label
      ref={ref}
      data-slot="switch-label"
      className={clsx(styles.label, normalizeClassName(className))}
      {...props}
    />
  );
});

const SwitchHiddenInput = forwardRef<
  ComponentRef<typeof SwitchPrimitive.HiddenInput>,
  ComponentProps<typeof SwitchPrimitive.HiddenInput>
>(function SwitchHiddenInput(props, ref) {
  return <SwitchPrimitive.HiddenInput ref={ref} data-slot="switch-hidden-input" {...props} />;
});

const SwitchContext = SwitchPrimitive.Context;

const Switch = Object.assign(SwitchRoot, {
  Root: SwitchRoot,
  RootProvider: SwitchRootProvider,
  Control: SwitchControl,
  Thumb: SwitchThumb,
  Label: SwitchLabel,
  HiddenInput: SwitchHiddenInput,
  Context: SwitchContext,
});

export { Switch, useSwitch, useSwitchContext };
export type {
  SwitchCheckedChangeDetails,
  SwitchContextProps,
  SwitchControlProps,
  SwitchHiddenInputProps,
  SwitchLabelProps,
  SwitchRootProps,
  SwitchRootProviderProps,
  SwitchThumbProps,
  UseSwitchContext,
  UseSwitchProps,
  UseSwitchReturn,
} from '@ark-ui/react/switch';

@layer ui.components {
  .root {
    display: inline-flex;
    align-items: center;
    gap: var(--switch-gap, var(--spacing-2));
    width: fit-content;
    vertical-align: middle;
    cursor: pointer;

    &[data-disabled],
    &[data-readonly] {
      cursor: default;
    }

    &[data-disabled] {
      opacity: var(--switch-disabled-opacity, var(--opacity-disabled));
    }
  }

  .control {
    box-sizing: border-box;
    position: relative;
    display: inline-flex;
    flex-shrink: 0;
    align-items: center;
    width: var(--switch-width, 2.5rem);
    height: var(--switch-height, 1.5rem);
    --switch-thumb-translate-default: calc(
      var(--switch-width, 2.5rem) - var(--switch-thumb-size, 1.125rem) -
        var(--switch-padding, 0.125rem) - var(--switch-padding, 0.125rem) -
        var(--switch-border-width, var(--border-width-sm)) -
        var(--switch-border-width, var(--border-width-sm))
    );
    border: var(--switch-border-width, var(--border-width-sm)) solid
      var(--switch-border-color, var(--color-border));
    border-radius: var(--switch-radius, var(--radius-full));
    padding: var(--switch-padding, 0.125rem);
    background-color: var(--switch-bg, var(--color-muted));
    outline: 0;
    line-height: 0;
    user-select: none;
    transition:
      background-color var(--switch-transition, var(--transition-default)),
      border-color var(--switch-transition, var(--transition-default)),
      opacity var(--switch-transition, var(--transition-default));

    &[data-state='checked'] {
      border-color: var(--switch-border-color-checked, var(--color-primary));
      background-color: var(--switch-bg-checked, var(--color-primary));
    }

    &[data-focus-visible] {
      outline: var(--switch-focus-ring-width, var(--border-width-sm)) solid
        var(--switch-focus-ring-color, var(--color-ring));
      outline-offset: var(--switch-focus-ring-offset, var(--border-width-sm));
    }

    @media (hover: hover) {
      &[data-state='unchecked'][data-hover]:not([data-readonly]) {
        background-color: var(--switch-bg-hover, var(--color-accent));
      }

      &[data-state='checked'][data-hover]:not([data-readonly]) {
        background-color: var(
          --switch-bg-checked-hover,
          var(--switch-bg-checked, var(--color-primary))
        );
      }
    }
  }

  .root[data-size='xs'] .control {
    --switch-width: var(--switch-width-xs, 1.75rem);
    --switch-height: var(--switch-height-xs, 1rem);
    --switch-thumb-size: var(--switch-thumb-size-xs, 0.625rem);
  }

  .root[data-size='sm'] .control {
    --switch-width: var(--switch-width-sm, 2rem);
    --switch-height: var(--switch-height-sm, 1.25rem);
    --switch-thumb-size: var(--switch-thumb-size-sm, 0.875rem);
  }

  .root[data-size='md'] .control {
    --switch-width: var(--switch-width-md, 2.5rem);
    --switch-height: var(--switch-height-md, 1.5rem);
    --switch-thumb-size: var(--switch-thumb-size-md, 1.125rem);
  }

  .root[data-size='lg'] .control {
    --switch-width: var(--switch-width-lg, 3rem);
    --switch-height: var(--switch-height-lg, 1.75rem);
    --switch-thumb-size: var(--switch-thumb-size-lg, 1.375rem);
  }

  .root[data-size='xl'] .control {
    --switch-width: var(--switch-width-xl, 3.5rem);
    --switch-height: var(--switch-height-xl, 2rem);
    --switch-thumb-size: var(--switch-thumb-size-xl, 1.625rem);
  }

  .thumb {
    display: inline-flex;
    align-items: center;
    justify-content: center;
    width: var(--switch-thumb-size, 1.125rem);
    height: var(--switch-thumb-size, 1.125rem);
    border: var(--switch-thumb-border-width, 0) solid var(--switch-thumb-border-color, transparent);
    border-radius: var(--switch-thumb-radius, var(--radius-full));
    background-color: var(
      --switch-thumb-bg-unchecked,
      var(--switch-thumb-bg, var(--color-background))
    );
    color: var(--switch-thumb-color-unchecked, var(--switch-thumb-color, var(--color-muted)));
    box-shadow: var(--switch-thumb-shadow, var(--shadow-sm));
    transform: translateX(0);
    transition:
      transform var(--switch-thumb-transition, var(--switch-transition, var(--transition-default))),
      background-color var(--switch-transition, var(--transition-default)),
      color var(--switch-transition, var(--transition-default));

    &[data-state='checked'] {
      background-color: var(
        --switch-thumb-bg-checked,
        var(--switch-thumb-bg, var(--color-primary-foreground))
      );
      color: var(--switch-thumb-color-checked, var(--switch-thumb-color, var(--color-primary)));
      transform: translateX(var(--switch-thumb-translate, var(--switch-thumb-translate-default)));
    }

    & > svg {
      width: var(--switch-thumb-icon-size, 65%);
      height: var(--switch-thumb-icon-size, 65%);
      flex-shrink: 0;
    }
  }

  .label {
    color: var(--switch-label-color, var(--color-foreground));
    font-size: var(--switch-label-font-size, var(--text-sm));
    font-weight: var(--switch-label-font-weight, var(--weight-medium));
    line-height: var(--switch-label-line-height, var(--line-height-text-sm));
    user-select: none;
  }
}
